Oto przykładowy kod programu w języku C++, który formatuje dysk twardy:

```c++
#include <iostream>
#include <windows.h>

using namespace std;

int main()
{
    char diskLetter;
    cout << "Podaj litere dysku do sformatowania (D, E, F, itd.): ";
    cin >> diskLetter;

    char volumeName[] = "\\\\.\\X:"; // zmien "X" na litere dysku
    volumeName[4] = diskLetter;

    HANDLE hVolume = CreateFile(volumeName,
                      GENERIC_READ | GENERIC_WRITE,
                      FILE_SHARE_READ | FILE_SHARE_WRITE,
                      NULL,
                      OPEN_EXISTING,
                      NULL,
                      NULL);

    DWORD bytesReturned;
    STORAGE_PROPERTY_QUERY spq = { 0 };
    spq.PropertyId = StorageDeviceProperty;
    spq.QueryType = PropertyStandardQuery;
    STORAGE_DEVICE_DESCRIPTOR sdd = { 0 };

    DeviceIoControl(hVolume,
                    IOCTL_STORAGE_QUERY_PROPERTY,
                    &spq,
                    sizeof(spq),
                    &sdd,
                    sizeof(sdd),
                    &bytesReturned,
                    NULL);

    DISK_GEOMETRY dg = { 0 };
    DeviceIoControl(hVolume,
                    IOCTL_DISK_GET_DRIVE_GEOMETRY,
                    NULL,
                    0,
                    &dg,
                    sizeof(dg),
                    &bytesReturned,
                    NULL);

    DWORD sectorSize = dg.BytesPerSector;
    DWORD totalSectors = sdd.Size >> 9;
    DWORD bytesToWrite = totalSectors * sectorSize;
    DWORD bytesWritten;

    cout << "Czy na pewno chcesz sformatowac dysk twardy? (T/N): ";
    char answer;
    cin >> answer;
    if (answer == 'T' || answer == 't')
    {
        char buffer[4096] = { 0 };
        memset(buffer, 0, 4096);

        // Usun partycję
        DeviceIoControl(hVolume,
                        FSCTL_DISMOUNT_VOLUME,
                        NULL,
                        0,
                        NULL,
                        0,
                        &bytesReturned,
                        NULL);
        DeviceIoControl(hVolume,
                        FSCTL_LOCK_VOLUME,
                        NULL,
                        0,
                        NULL,
                        0,
                        &bytesReturned,
                        NULL);
        DeviceIoControl(hVolume,
                        FSCTL_DELETE_VOLUME,
                        NULL,
                        0,
                        NULL,
                        0,
                        &bytesReturned,
                        NULL);

        // Sformatuj dysk
        SetFilePointer(hVolume, 0, NULL, FILE_BEGIN);
        WriteFile(hVolume, buffer, 4096, &bytesWritten, NULL);
        for (DWORD i = 1; i < totalSectors; i++)
        {
            WriteFile(hVolume, buffer, 4096, &bytesWritten, NULL);
        }

        // Zakończ proces
        DeviceIoControl(hVolume,
                        FSCTL_UNLOCK_VOLUME,
                        NULL,
                        0,
                        NULL,
                        0,
                        &bytesReturned,
                        NULL);
        CloseHandle(hVolume);
